    if (neural_valid && (neural_result[1:0] == TRIT_POS)) begin
      $display("✓ PASS: Neural ACTIVATE test - result = +1");
      test_passed = 1'b1;
    end else begin
      $display("✗ FAIL: Neural ACTIVATE test - got %b, expected %b", neural_result[1:0], TRIT_POS);
      test_passed = 1'b0;
    end

    test_count++;
  endtask

  task automatic test_register_boundaries();
    logic [31:0] test_data_t0, test_data_t31, test_data_t15;
    logic        all_passed;

    $display("Testing register boundary conditions (T0, T15, T31)");
    all_passed = 1'b1;

    // Test T0 (lowest boundary)
    test_data_t0 = 32'h12345678;
    $display("  Testing T0 (address 0)...");
    write_ternary_reg(5'd0, test_data_t0);
    read_ternary_reg(5'd0, 5'd0);

    if (trf_rdata_a == test_data_t0) begin
      $display("  ✓ PASS: T0 write/read test");
    end else begin
      $display("  ✗ FAIL: T0 write/read test - got %h, expected %h", trf_rdata_a, test_data_t0);
      all_passed = 1'b0;
    end

    // Test T15 (middle boundary)
    test_data_t15 = 32'h9ABCDEF0;
    $display("  Testing T15 (address 15)...");
    write_ternary_reg(5'd15, test_data_t15);
    read_ternary_reg(5'd15, 5'd15);

    if (trf_rdata_a == test_data_t15) begin
      $display("  ✓ PASS: T15 write/read test");
    end else begin
      $display("  ✗ FAIL: T15 write/read test - got %h, expected %h", trf_rdata_a, test_data_t15);
      all_passed = 1'b0;
    end

    // Test T31 (highest boundary)
    test_data_t31 = 32'hFEDCBA98;
    $display("  Testing T31 (address 31)...");
    write_ternary_reg(5'd31, test_data_t31);
    read_ternary_reg(5'd31, 5'd31);

    if (trf_rdata_a == test_data_t31) begin
      $display("  ✓ PASS: T31 write/read test");
    end else begin
      $display("  ✗ FAIL: T31 write/read test - got %h, expected %h", trf_rdata_a, test_data_t31);
      all_passed = 1'b0;
    end

    // Test simultaneous read from T0 and T31
    $display("  Testing simultaneous read from T0 and T31...");
    read_ternary_reg(5'd0, 5'd31);

    if (trf_rdata_a == test_data_t0 && trf_rdata_b == test_data_t31) begin
      $display("  ✓ PASS: Simultaneous T0/T31 read test");
    end else begin
      $display("  ✗ FAIL: Simultaneous T0/T31 read test");
      $display("    T0: got %h, expected %h", trf_rdata_a, test_data_t0);
      $display("    T31: got %h, expected %h", trf_rdata_b, test_data_t31);
      all_passed = 1'b0;
    end

    if (all_passed) begin
      $display("✓ PASS: All register boundary tests passed");
      test_passed = 1'b1;
    end else begin
      $display("✗ FAIL: Some register boundary tests failed");
      test_passed = 1'b0;
    end

    test_count++;
  endtask

  ////////////////////////////////////////////////
  // Main Test Sequence                         //
  ////////////////////////////////////////////////

  initial begin
    $display("=================================================");
    $display("MHX Ternary Extension Test");
    $display("=================================================");

    // Initialize
    clk = 0;
    test_count = 0;
    test_passed = 1'b0;

    // Initialize control signals
    trf_we = 1'b0;
    trf_waddr = 5'b0;
    trf_wdata = 32'h0;
    trf_raddr_a = 5'b0;
    trf_raddr_b = 5'b0;
    talu_op = TERNARY_ADD;
    neural_op = NEURAL_MULTIPLY;
    neural_weights = 32'h0;
    neural_inputs = 32'h0;
    neural_bias = 32'h0;

    // Reset
    reset_dut();

    $display("\n--- Testing Ternary Register File ---");

    // Test register write/read
    $display("Testing register write/read...");
    write_ternary_reg(5'd5, 32'hDEADBEEF);
    read_ternary_reg(5'd5, 5'd0);

    if (trf_rdata_a == 32'hDEADBEEF) begin
      $display("✓ PASS: Register file write/read test");
    end else begin
      $display("✗ FAIL: Register file write/read test");
    end
    test_count++;

    // Test register boundary conditions
    test_register_boundaries();

    $display("\n--- Testing Ternary ALU ---");

    // Test ternary arithmetic operations
    // Note: Using simplified test values for demonstration

    // Test ADD: 0 + 1 = 1 (in ternary encoding)
    test_ternary_add(32'h55555555, 32'hAAAAAAAA, 32'hAAAAAAAA);

    // Test MUL: 1 * 1 = 1 (in ternary encoding)
    test_ternary_mul(32'hAAAAAAAA, 32'hAAAAAAAA, 32'hAAAAAAAA);

    // Test ALU operations with boundary registers (T0 and T31)
    $display("Testing ALU with boundary registers T0 and T31...");
    write_ternary_reg(5'd0, 32'h12345678);   // T0 = test value
    write_ternary_reg(5'd31, 32'h87654321);  // T31 = test value
    read_ternary_reg(5'd0, 5'd31);

    // Verify registers were read correctly before ALU operation
    if (trf_rdata_a == 32'h12345678 && trf_rdata_b == 32'h87654321) begin
      // Perform any ALU operation to verify boundary registers work with ALU
      talu_op = TERNARY_ADD;
      repeat(2) @(posedge clk);

      // Just verify ALU produces a result - we're testing addressing, not arithmetic correctness
      if (talu_ready) begin
        $display("✓ PASS: ALU operation with T0 and T31 boundary registers");
        test_passed = 1'b1;
      end else begin
        $display("✗ FAIL: ALU not ready for boundary register operation");
        test_passed = 1'b0;
      end
    end else begin
      $display("✗ FAIL: Boundary registers not read correctly for ALU operation");
      test_passed = 1'b0;
    end
    test_count++;

    $display("\n--- Testing Neural Unit ---");

    // Test neural operations
    test_neural_multiply();
    test_neural_activate();

    $display("\n=================================================");
    $display("Test Summary: %d tests completed", test_count);
    if (test_count > 0) begin
      $display("MHX Ternary Extension tests completed!");
    end
    $display("=================================================");

    $finish;
  end

  // Timeout
  initial begin
    #50000;
    $display("ERROR: Test timeout!");
    $finish;
  end

endmodule

